struct Disk(i32);
impl BlockDevice for Disk {
    fn read_offset(&self, offset: usize) -> Vec<u8> {
        let max = BSIZE as usize - offset % BSIZE as usize;
        let mut v = vec![0u8; max];
        let addr = v.as_mut_ptr() as _;
        // println!("rs::read_offset: {}", offset);
        let cnt = unsafe { breadoffset(self.0 as _, offset as _, addr, max as _) };
        v.truncate(cnt as _);
        trace!("read_offset: offset: {} len: {}", offset, v.len());
        v
    }

    fn write_offset(&self, offset: usize, data: &[u8]) {
        unsafe {
            bwriteoffset(
                self.0 as _,
                offset as _,
                data.as_ptr() as _,
                data.len() as _,
            );
        }
    }
}

